import { describe, expect, it } from 'vitest';

import {
  LENS_FACTOR_HEXON_TO_TRIHEXENNEON,
  LensingMaster,
  TRIHEXENNEON_IS_NINE_HEXONS,
  lensAddress,
  lensAddressReconstructRoundtrip,
  lensDescent,
  lensPreservesUnitCost,
  lensReconstruct,
  lensReconstructAddressRoundtrip,
  tritonStretchDivRecovers,
  tritonStretchInjective,
} from '../src/pleromatic-lensing';

describe('Pleromatic lensing constants', () => {
  it('lens factor Hexon→Trihexenneon is 9', () => {
    expect(LENS_FACTOR_HEXON_TO_TRIHEXENNEON).toBe(9);
  });

  it('TRIHEXENNEON_IS_NINE_HEXONS: 9 × 6 = 54', () => {
    expect(TRIHEXENNEON_IS_NINE_HEXONS).toBe(54);
    expect(9 * 6).toBe(TRIHEXENNEON_IS_NINE_HEXONS);
  });
});

describe('Triton-stretch injectivity / recovery (mirrors triton_stretch_*)', () => {
  it('triton_stretch_injective: 3*m = 3*n implies m = n', () => {
    for (let m = 0; m <= 10; m++) {
      for (let n = 0; n <= 10; n++) {
        expect(tritonStretchInjective(m, n)).toBe(true);
      }
    }
  });

  it('triton_stretch_div_recovers: (3*n)/3 = n for n=0..10', () => {
    for (let n = 0; n <= 10; n++) {
      expect(tritonStretchDivRecovers(n)).toBe(n);
    }
  });
});

describe('Lens compression view (mirrors lens_descent_*)', () => {
  it('lens_descent_compression: lensDescent(9*n) = n for n=0..5', () => {
    for (let n = 0; n <= 5; n++) {
      expect(lensDescent(9 * n)).toBe(n);
    }
  });

  it('lens_descent_collapses_nine_copies: lensDescent(0..8) all = 0', () => {
    for (let k = 0; k <= 8; k++) {
      expect(lensDescent(k)).toBe(0);
    }
  });
});

describe('Lens lossless view (mirrors lens_address_*)', () => {
  it('lens_address_reconstruct_roundtrip: holds for k=0..100', () => {
    for (let k = 0; k <= 100; k++) {
      expect(lensReconstruct(lensAddress(k))).toBe(k);
      expect(lensAddressReconstructRoundtrip(k)).toBe(true);
    }
  });

  it('lens_reconstruct_address_roundtrip: holds for q=0..10, r=0..8', () => {
    for (let q = 0; q <= 10; q++) {
      for (let r = 0; r <= 8; r++) {
        expect(lensReconstructAddressRoundtrip(q, r)).toBe(true);
        const round = lensAddress(lensReconstruct({ hexonPosition: q, copyIndex: r }));
        expect(round).toEqual({ hexonPosition: q, copyIndex: r });
      }
    }
  });

  it('lens_address_eighteen: lensAddress(18) = {2, 0}', () => {
    expect(lensAddress(18)).toEqual({ hexonPosition: 2, copyIndex: 0 });
  });

  it('lens_address_twentyseven: lensAddress(27) = {3, 0}', () => {
    expect(lensAddress(27)).toEqual({ hexonPosition: 3, copyIndex: 0 });
  });

  it('lens_address_fiftythree: lensAddress(53) = {5, 8}', () => {
    expect(lensAddress(53)).toEqual({ hexonPosition: 5, copyIndex: 8 });
  });
});

describe('Bule cost preservation (mirrors lens_preserves_unit_cost)', () => {
  it('lensPreservesUnitCost(k) = 1 for various k', () => {
    for (const k of [0, 1, 2, 7, 8, 9, 17, 18, 26, 27, 52, 53, 100]) {
      expect(lensPreservesUnitCost(k)).toBe(1);
    }
  });
});

describe('LensingMaster bundle', () => {
  it('factor and trihexenneon constants match', () => {
    expect(LensingMaster.factor).toBe(9);
    expect(LensingMaster.trihexenneonIsNineHexons).toBe(54);
  });

  it('sample addresses match Lean theorems', () => {
    expect(LensingMaster.sampleAddresses.eighteen).toEqual({ hexonPosition: 2, copyIndex: 0 });
    expect(LensingMaster.sampleAddresses.twentyseven).toEqual({ hexonPosition: 3, copyIndex: 0 });
    expect(LensingMaster.sampleAddresses.fiftythree).toEqual({ hexonPosition: 5, copyIndex: 8 });
  });

  it('roundtrip witnesses all hold', () => {
    expect(LensingMaster.roundtripWitnesses.addressReconstructAtZero).toBe(true);
    expect(LensingMaster.roundtripWitnesses.addressReconstructAtFiftythree).toBe(true);
    expect(LensingMaster.roundtripWitnesses.reconstructAddressAtFiveEight).toBe(true);
  });
});
